(window.webpackJsonp=window.webpackJsonp||[]).push([[220],{847:function(n,r){n.exports="\x3c!-- \r\ntitle: Redis\r\nsort: \r\n--\x3e \r\n\r\n> 以键值对方式存储数据\r\n\r\n```bash\r\n# 连接服务\r\nredis-cli -h host -p port -a password\r\n# 默认端口6379\r\n```\r\n\r\n## 基础命令\r\n\r\n> 对键值对的操纵\r\n\r\n```sql\r\n-- 添加\r\nset <key_name> <value>\r\n-- 查询\r\nget <key_name>\r\n-- 删除\r\ndel <key_name>\r\n-- 批量\r\nmset key1 hello key2 world\r\nmget key1 key2\r\n\r\n-- hash 操作\r\nhset hash1 name fzf age 18\r\nhget hash1 name\r\nhgetall hash1\r\nhdel hash1 name\r\n\r\n-- list 操作\r\n-- 链表\r\nlpush line1 value1 value2\r\nlrange line1 0 -1\r\n-- 从第0个到结尾\r\n\r\n-- set 操作\r\n-- 存入无法改变\r\nsadd set1 value1 value2\r\n\r\n-- 删库\r\nflushall\r\n-- 换库\r\nselect <index>\r\n```\r\n\r\n"}}]);